package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.JsonElement;
import com.google.gson.JsonIOException;
import com.google.gson.internal.GsonBuildConfig;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;
import org.mockito.Mockito;

public class GsonTest {

  private Gson gson;
  private JsonWriter writer;
  private JsonElement jsonElement;

  @BeforeEach
  public void setUp() {
    gson = new Gson();
    writer = mock(JsonWriter.class);
    jsonElement = mock(JsonElement.class);
  }

  @Test
  public void toJson_shouldWriteJsonElementAndRestoreWriterSettings() throws IOException {
    // Setup writer mocks for initial states
    when(writer.isLenient()).thenReturn(false);
    when(writer.isHtmlSafe()).thenReturn(false);
    when(writer.getSerializeNulls()).thenReturn(false);

    // Call method under test
    gson.toJson(jsonElement, writer);

    // Verify writer state changes in order
    InOrder inOrder = inOrder(writer);
    inOrder.verify(writer).isLenient();
    inOrder.verify(writer).setLenient(true);
    inOrder.verify(writer).isHtmlSafe();
    inOrder.verify(writer).setHtmlSafe(gson.htmlSafe());
    inOrder.verify(writer).getSerializeNulls();
    inOrder.verify(writer).setSerializeNulls(gson.serializeNulls());

    // Verify Streams.write called (indirectly verified by no exception and no interaction with jsonElement)
    // Since Streams.write is static and not mockable here, we assume no exception means success.

    // Verify writer settings restored
    inOrder.verify(writer).setLenient(false);
    inOrder.verify(writer).setHtmlSafe(false);
    inOrder.verify(writer).setSerializeNulls(false);
  }

  @Test
  public void toJson_shouldThrowJsonIOException_whenIOExceptionOccurs() throws IOException {
    // Setup writer mocks
    when(writer.isLenient()).thenReturn(true);
    when(writer.isHtmlSafe()).thenReturn(true);
    when(writer.getSerializeNulls()).thenReturn(true);

    // Mock Streams.write to throw IOException by spying on Gson and using reflection to replace Streams.write
    // Since Streams.write is static and final, we simulate by mocking writer behavior that triggers IOException in Streams.write
    // Instead, we simulate by throwing IOException from Streams.write call by creating a JsonElement that throws IOException on toString
    JsonElement throwingJsonElement = new JsonElement() {
      @Override
      public String toString() {
        throw new RuntimeException("Should not be called");
      }
    };

    // We spy on Gson to override Streams.write call using reflection is complicated, so we test exception wrapping by invoking private method
    // Instead, we simulate IOException by mocking writer to throw IOException when Streams.write is called
    doThrow(new IOException("ioexception")).when(writer).setLenient(anyBoolean());

    JsonWriter writerThrowingIOException = mock(JsonWriter.class);
    when(writerThrowingIOException.isLenient()).thenReturn(true);
    when(writerThrowingIOException.isHtmlSafe()).thenReturn(true);
    when(writerThrowingIOException.getSerializeNulls()).thenReturn(true);

    // To simulate IOException during Streams.write, we create a subclass of Gson with overridden toJson calling Streams.write throwing IOException
    // But since not possible, we test the catch block by invoking the method with a mock JsonWriter that throws IOException on Streams.write call
    // Alternative: mock Streams.write static method with PowerMockito or similar, but not allowed here.
    // So we test by creating a custom JsonWriter that throws IOException on any method called by Streams.write
    JsonWriter throwingWriter = new JsonWriter(new java.io.StringWriter()) {
      @Override
      public void flush() throws IOException {
        throw new IOException("flush IOException");
      }
    };

    // Use real Gson but catch JsonIOException thrown from toJson
    JsonWriter spyWriter = spy(throwingWriter);

    assertThrows(JsonIOException.class, () -> gson.toJson(jsonElement, spyWriter));
  }

  @Test
  public void toJson_shouldWrapAssertionErrorWithVersion() throws IOException {
    // Create JsonWriter that throws AssertionError when Streams.write is called
    JsonWriter throwingWriter = new JsonWriter(new java.io.StringWriter()) {
      @Override
      public void flush() throws IOException {
        throw new AssertionError("assertion error");
      }
    };

    JsonWriter spyWriter = spy(throwingWriter);

    AssertionError thrown = assertThrows(AssertionError.class, () -> gson.toJson(jsonElement, spyWriter));
    assertTrue(thrown.getMessage().contains("AssertionError (GSON " + GsonBuildConfig.VERSION + "): assertion error"));
  }
}
